import React, { useEffect } from 'react';
import styled from 'styled-components';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Footer from '../components/Footer';
import { useTheme } from '../context/ThemeContext';

const TeamPage = styled.div`
  min-height: 100vh;
  background: ${props => props.theme.background};
  padding-top: 80px;
  transition: background-color 0.3s ease;
`;

const TeamSection = styled.section`
  padding: 100px 10%;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const TeamGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-top: 50px;
`;

const TeamCard = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  padding: 20px;
  text-align: center;
  transition: all 0.3s ease;

  h3 {
    color: ${props => props.theme.primary};
    margin: 10px 0;
  }

  p {
    color: ${props => props.theme.text};
    margin: 5px 0;
  }

  img {
    width: 150px;
    height: 150px;
    border-radius: 50%;
    object-fit: cover;
    transition: transform 0.3s ease;
  }

  &:hover img {
    transform: scale(1.05);
  }
`;

const Team = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true,
      mirror: false
    });
  }, []);

  const teamMembers = [
    {
      name: "Charchit",
      position: "CEO & Founder",
      image: "assets/charchit1.jpeg",
      instagram: "https://www.instagram.com/charchit.singh_16/",
      linkedin: "#"
    },
    {
      name: "Ayush Samant",
      position: "COO",
      image: "images/ayush_samant.jpg",
      instagram: "#",
      linkedin: "#"
    },
    {
      name: "Neelansh",
      position: "COO",
      image: "images/neelansh.jpeg",
      instagram: "https://www.instagram.com/neelansh_pratap_singh?igsh=bmRzZW5sb2w0dmRi",
      linkedin: "https://www.linkedin.com/in/neelansh-singh-894852218?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app"
    },
    {
      name: "Mayank",
      position: "Marketing Head",
      image: "images/mayank.jpeg",
      instagram: "https://www.instagram.com/m01ayank0?igsh=cDZvd2JncTBmam5s",
      linkedin: "https://www.linkedin.com/in/mayank-dhusia-807b3335a?utm_source=share&utm_campaign=share_via&utm_content=profile&utm_medium=android_app"
    },
    {
      name: "Piyush Saini",
      position: "Technical Lead",
      image: "images/piyush.jpg",
      instagram: "http://instagram.com/piyush_saini_40",
      linkedin: "https://www.linkedin.com/in/piyushsaini2004/"
    },
    {
      name: "Ayush Yadav",
      position: "Social Media Head",
      image: "images/ayush yadav.JPEG",
      instagram: "https://www.instagram.com/ayusx_h",
      linkedin: "https://www.linkedin.com/me?trk=p_mwlite_feed-secondary_nav"
    },
    {
      name: "Bhanu",
      position: "Media Head",
      image: "images/bhanu_picture.jpg",
      instagram: "https://optimusorgz.github.io/Optimusorgz/team.html#",
      linkedin: "https://optimusorgz.github.io/Optimusorgz/team.html#"
    },
    // Add more team members here
  ];

  return (
    <TeamPage theme={theme}>
      <TeamSection>
        <Header>
          <h2 data-aos="fade-up">Our Team</h2>
        </Header>
        <TeamGrid>
          {teamMembers.map((member, index) => (
            <TeamCard 
              key={index} 
              data-aos="fade-up" 
              data-aos-delay={100 * (index + 1)}
              theme={theme}
            >
              <img src={member.image} alt={member.name} />
              <h3>{member.name}</h3>
              <p>{member.position}</p>
              <div className="social-icons">
                <a href={member.instagram} target="_blank" rel="noopener noreferrer">
                  <i className="fab fa-instagram"></i>
                </a>
                <a href={member.linkedin} target="_blank" rel="noopener noreferrer">
                  <i className="fab fa-linkedin-in"></i>
                </a>
              </div>
            </TeamCard>
          ))}
        </TeamGrid>
      </TeamSection>
      <Footer />
    </TeamPage>
  );
};

export default Team;
